const SPL_TOKEN_PROGRAM_ID = new PublicKey("TokenkegQfeZyiNwAJbNbGKPFXCWuBvf9Ss623VQ5DA");
const IX_MATCH_LOCKED_INTENT_ESCROWED = "match_locked_intent_escrowed";
const IX_SETTLE_TWO_SIDED = "settle_two_sided";

// Status constants
const STATUS_SETTLED = 2;
const STATUS_LOCKED_ESCROWED = 6;
const STATUS_MATCHED_ESCROWED = 7;
const VAULT_STATUS_DEPOSITED = 1;
const LOCK_MATCH_STATUS_FILLED = 1;

// PrivateIntent offsets / size
const INTENT_TRADER_OFFSET = 8;
const INTENT_EXPIRES_AT_OFFSET = 104;
const INTENT_STATUS_OFFSET = 112;
const INTENT_SPACE = 193;
// IntentVaultRecord offsets
const VAULT_INPUT_MINT_OFFSET = 104;
const VAULT_TOKEN_ACCOUNT_OFFSET = 136;
const VAULT_DEPOSITED_AMOUNT_OFFSET = 233;
const VAULT_STATUS_OFFSET = 241;
// Match record offsets
const MATCH_FILL_HASH_OFFSET = 232;
const MATCH_MATCHED_AMOUNT_OFFSET = 264;
const MATCH_STATUS_OFFSET = 280;
// SPL token account offsets
const TOKEN_MINT_OFFSET = 0;
const TOKEN_OWNER_OFFSET = 32;
const TOKEN_AMOUNT_OFFSET = 64;

// ===================== Byte helpers =====================
function readU8(buf: Buffer, off: number): number { return buf[off]; }
function readI64LE(buf: Buffer, off: number): bigint { return buf.readBigInt64LE(off); }
function readU64LE(buf: Buffer, off: number): bigint { return buf.readBigUInt64LE(off); }
function readPubkey(buf: Buffer, off: number): PublicKeyT { return new PublicKey(buf.subarray(off, off + 32)); }
function u64LE(value: number | bigint): Buffer {
  const b = Buffer.alloc(8);
  b.writeBigUInt64LE(BigInt(value));
  return b;
}

// ===================== PDA / hash helpers =====================
function anchorDiscriminator(name: string): Buffer {
  return createHash("sha256").update(`global:${name}`).digest().subarray(0, 8);
}
function derivePda(seed: string, extra: Buffer | null, programId: PublicKeyT): PublicKeyT {
  const seeds = extra ? [Buffer.from(seed), extra] : [Buffer.from(seed)];
  return PublicKey.findProgramAddressSync(seeds, programId)[0];
}
function deriveAta(owner: PublicKeyT, mint: PublicKeyT): PublicKeyT {
  return PublicKey.findProgramAddressSync(
    [owner.toBuffer(), SPL_TOKEN_PROGRAM_ID.toBuffer(), mint.toBuffer()],
    new PublicKey("ATokenGPvbdGVxr1b2hvZbsiqW5xWH25efTNsLJA8knL")
  )[0];
}
function deriveMatchFillHash(intentPda: PublicKeyT, matchedAmount: number): Buffer {
  return createHash("sha256")
    .update(`match-fill-commitment-escrowed:${intentPda.toBase58()}:${matchedAmount}`)
    .digest();
}
interface EscrowPdas {
  configPda: PublicKeyT;
  intentVaultPda: PublicKeyT;
  matchRecordPda: PublicKeyT;
  vaultAuthorityPda: PublicKeyT;
}
function deriveEscrowPdas(programId: PublicKeyT, intentPda: PublicKeyT): EscrowPdas {
  const intentVaultPda = derivePda(SEEDS.intentVault, intentPda.toBuffer(), programId);
  return {
    configPda: derivePda(SEEDS.config, null, programId),
    intentVaultPda,
    matchRecordPda: derivePda(SEEDS.intentMatchEscrowed, intentPda.toBuffer(), programId),
    vaultAuthorityPda: derivePda(SEEDS.intentVaultAuthority, intentVaultPda.toBuffer(), programId),
  };
}

// ===================== Instruction builders =====================
interface BuiltIx { ix: anchor.web3.TransactionInstruction; data: Buffer; keys: AccountMeta[]; pdas: EscrowPdas; }
interface BuiltMatchIx extends BuiltIx { fillHash: Buffer; }
function buildMatchEscrowedIx(input: {
  programId: PublicKeyT; intentPda: PublicKeyT; solver: PublicKeyT; matchedAmount: number; fillHash?: Buffer;
}): BuiltMatchIx {
  const { programId, intentPda, solver, matchedAmount } = input;
  const pdas = deriveEscrowPdas(programId, intentPda);
  const fillHash = input.fillHash ?? deriveMatchFillHash(intentPda, matchedAmount);
  const data = Buffer.concat([anchorDiscriminator(IX_MATCH_LOCKED_INTENT_ESCROWED), fillHash, u64LE(matchedAmount)]);
  const keys: AccountMeta[] = [
    { pubkey: pdas.configPda, isSigner: false, isWritable: false },
    { pubkey: intentPda, isSigner: false, isWritable: true },
    { pubkey: pdas.intentVaultPda, isSigner: false, isWritable: false },
    { pubkey: pdas.matchRecordPda, isSigner: false, isWritable: true },
    { pubkey: solver, isSigner: true, isWritable: true },
    { pubkey: SystemProgram.programId, isSigner: false, isWritable: false },
  ];
  return { ix: new TransactionInstruction({ programId, keys, data }), data, keys, pdas, fillHash };
}
function buildSettleTwoSidedIx(input: {
  programId: PublicKeyT; intentPda: PublicKeyT; solver: PublicKeyT; outputAmount: number; fillHash: Buffer;
  vaultTokenAccount: PublicKeyT; solverOutputSource: PublicKeyT; traderOutputDest: PublicKeyT; solverInputDest: PublicKeyT;
}): BuiltIx {
  const { programId, intentPda, solver, outputAmount, fillHash } = input;
  const pdas = deriveEscrowPdas(programId, intentPda);
  const data = Buffer.concat([anchorDiscriminator(IX_SETTLE_TWO_SIDED), u64LE(outputAmount), fillHash]);
  const keys: AccountMeta[] = [
    { pubkey: pdas.configPda, isSigner: false, isWritable: false },
    { pubkey: intentPda, isSigner: false, isWritable: true },
    { pubkey: pdas.matchRecordPda, isSigner: false, isWritable: true },
    { pubkey: pdas.intentVaultPda, isSigner: false, isWritable: true },
    { pubkey: pdas.vaultAuthorityPda, isSigner: false, isWritable: false },
    { pubkey: input.vaultTokenAccount, isSigner: false, isWritable: true },
    { pubkey: input.solverOutputSource, isSigner: false, isWritable: true },
    { pubkey: input.traderOutputDest, isSigner: false, isWritable: true },
    { pubkey: input.solverInputDest, isSigner: false, isWritable: true },
    { pubkey: solver, isSigner: true, isWritable: true },
    { pubkey: SPL_TOKEN_PROGRAM_ID, isSigner: false, isWritable: false },
  ];
  return { ix: new TransactionInstruction({ programId, keys, data }), data, keys, pdas };
}

// ===================== Token-account read =====================
interface TokenAccount { mint: PublicKeyT; owner: PublicKeyT; amount: bigint; }
async function readTokenAccount(connection: anchor.web3.Connection, addr: PublicKeyT): Promise<TokenAccount | null> {
  const ai = await connection.getAccountInfo(addr);
  if (!ai || !ai.owner.equals(SPL_TOKEN_PROGRAM_ID) || ai.data.length < 72) return null;
  return {
    mint: readPubkey(ai.data, TOKEN_MINT_OFFSET),
    owner: readPubkey(ai.data, TOKEN_OWNER_OFFSET),
    amount: readU64LE(ai.data, TOKEN_AMOUNT_OFFSET),
  };
}

// ===================== Discovery (READ-ONLY) =====================
type SkipReason = "already-matched" | "expired" | "vault-not-deposited" | "vault-missing";
interface DiscoveredIntent {
  intentPda: string; trader: string; intentVault: string; matchRecord: string;
  status: number; vaultStatus: number | null; depositedAmount: string | null; inputMint: string | null;
  expiresAt: string; expired: boolean; matchExists: boolean; actionable: boolean; skipReason: SkipReason | null;
}
function privateIntentDiscriminator(): Buffer {
  const acc = (IDL.accounts || []).find((a: any) => a.name === "PrivateIntent");
  if (!acc || !Array.isArray(acc.discriminator) || acc.discriminator.length !== 8) {
    throw new Error("PrivateIntent discriminator not found in embedded IDL");
  }
  return Buffer.from(acc.discriminator);
}
function classify(facts: { expired: boolean; matchExists: boolean; vaultStatus: number | null }): {
  actionable: boolean; skipReason: SkipReason | null;
} {
  if (facts.matchExists) return { actionable: false, skipReason: "already-matched" };
  if (facts.vaultStatus === null) return { actionable: false, skipReason: "vault-missing" };
  if (facts.vaultStatus !== VAULT_STATUS_DEPOSITED) return { actionable: false, skipReason: "vault-not-deposited" };
  if (facts.expired) return { actionable: false, skipReason: "expired" };
  return { actionable: true, skipReason: null };
}
async function discoverActionableIntents(
  connection: anchor.web3.Connection,
  programId: PublicKeyT,
  nowSec: bigint = BigInt(Math.floor(Date.now() / 1000))
): Promise<DiscoveredIntent[]> {
  const disc = privateIntentDiscriminator();
  const statusBytes = Buffer.from([STATUS_LOCKED_ESCROWED]);
  const found = await connection.getProgramAccounts(programId, {
    commitment: "confirmed",
    filters: [
      { dataSize: INTENT_SPACE },
      { memcmp: { offset: 0, bytes: anchor.utils.bytes.bs58.encode(disc) } },
      { memcmp: { offset: INTENT_STATUS_OFFSET, bytes: anchor.utils.bytes.bs58.encode(statusBytes) } },
    ],
  });
  const results: DiscoveredIntent[] = [];
  for (const { pubkey: intentPda, account } of found) {
    const data = account.data;
    const trader = readPubkey(data, INTENT_TRADER_OFFSET);
    const status = readU8(data, INTENT_STATUS_OFFSET);
    const expiresAt = readI64LE(data, INTENT_EXPIRES_AT_OFFSET);
    const expired = nowSec >= expiresAt;
    const { intentVaultPda, matchRecordPda } = deriveEscrowPdas(programId, intentPda);
    const [vaultInfo, matchInfo] = await Promise.all([
      connection.getAccountInfo(intentVaultPda),
      connection.getAccountInfo(matchRecordPda),
    ]);
    const vaultStatus = vaultInfo ? readU8(vaultInfo.data, VAULT_STATUS_OFFSET) : null;
    const depositedAmount = vaultInfo ? readU64LE(vaultInfo.data, VAULT_DEPOSITED_AMOUNT_OFFSET) : null;
    const inputMint = vaultInfo ? readPubkey(vaultInfo.data, VAULT_INPUT_MINT_OFFSET) : null;
    const matchExists = matchInfo !== null;
    const { actionable, skipReason } = classify({ expired, matchExists, vaultStatus });
    results.push({
      intentPda: intentPda.toBase58(), trader: trader.toBase58(), intentVault: intentVaultPda.toBase58(),
      matchRecord: matchRecordPda.toBase58(), status, vaultStatus,
      depositedAmount: depositedAmount === null ? null : depositedAmount.toString(),
      inputMint: inputMint ? inputMint.toBase58() : null, expiresAt: expiresAt.toString(),
      expired, matchExists, actionable, skipReason,
    });
  }
  return results;
}

// ===================== Per-intent plan + execute =====================
type FlowPhase = "full" | "resume-settle" | "done" | "skip";
interface IntentPlan {
  intentPda: string; trader: string; inputMint: string; outputMint: string | null;
  depositedAmount: string; matchedAmount: number | null; outputAmount: number | null;
  intentStatus: number; expired: boolean; matchExists: boolean; phase: FlowPhase; skipReason: string | null;
  solverOutputAta: string | null; solverOutputBalance: string | null; inventoryRequired: number | null;
  inventoryOk: boolean; traderOutputAta: string | null; traderAtaOk: boolean;
  vaultTokenAccount: string | null; solverInputDest: string | null; fillHash: string | null;
  matchBuilt: BuiltMatchIx | null; settleBuilt: BuiltIx | null;
}
function findPairForInputMint(pairs: PairConfig[], inputMint: string): PairConfig | null {
  return pairs.find((p) => p.status === "active" && p.input_mint === inputMint) || null;
}
async function planIntentFlow(
  connection: anchor.web3.Connection,
  programId: PublicKeyT,
  intentPda: PublicKeyT,
  pairs: PairConfig[],
  solver: PublicKeyT,
  nowSec: bigint = BigInt(Math.floor(Date.now() / 1000))
): Promise<IntentPlan> {
  const { intentVaultPda, matchRecordPda } = deriveEscrowPdas(programId, intentPda);
  const [intentInfo, vaultInfo, matchInfo] = await Promise.all([
    connection.getAccountInfo(intentPda),
    connection.getAccountInfo(intentVaultPda),
    connection.getAccountInfo(matchRecordPda),
  ]);
  const base: IntentPlan = {
    intentPda: intentPda.toBase58(), trader: "", inputMint: "", outputMint: null, depositedAmount: "0",
    matchedAmount: null, outputAmount: null, intentStatus: -1, expired: false, matchExists: matchInfo !== null,
    phase: "skip", skipReason: null, solverOutputAta: null, solverOutputBalance: null, inventoryRequired: null,
    inventoryOk: false, traderOutputAta: null, traderAtaOk: false, vaultTokenAccount: null, solverInputDest: null,
    fillHash: null, matchBuilt: null, settleBuilt: null,
  };
  if (!intentInfo) return { ...base, skipReason: "intent-missing" };
  if (!vaultInfo) return { ...base, skipReason: "vault-missing" };

  const trader = readPubkey(intentInfo.data, INTENT_TRADER_OFFSET);
  const intentStatus = readU8(intentInfo.data, INTENT_STATUS_OFFSET);
  const expiresAt = readI64LE(intentInfo.data, INTENT_EXPIRES_AT_OFFSET);
  const expired = nowSec >= expiresAt;
  const inputMint = readPubkey(vaultInfo.data, VAULT_INPUT_MINT_OFFSET);
  const vaultStatus = readU8(vaultInfo.data, VAULT_STATUS_OFFSET);
  const depositedAmount = readU64LE(vaultInfo.data, VAULT_DEPOSITED_AMOUNT_OFFSET);
  const vaultTokenAccount = readPubkey(vaultInfo.data, VAULT_TOKEN_ACCOUNT_OFFSET);

  base.trader = trader.toBase58();
  base.inputMint = inputMint.toBase58();
  base.intentStatus = intentStatus;
  base.expired = expired;
  base.depositedAmount = depositedAmount.toString();
  base.vaultTokenAccount = vaultTokenAccount.toBase58();

  let phase: FlowPhase;
  if (intentStatus === STATUS_SETTLED) return { ...base, phase: "done", skipReason: "already-settled" };
  if (intentStatus === STATUS_MATCHED_ESCROWED && base.matchExists) phase = "resume-settle";
  else if (intentStatus === STATUS_LOCKED_ESCROWED && !base.matchExists) phase = "full";
  else return { ...base, phase: "skip", skipReason: `unexpected-state(status=${intentStatus},match=${base.matchExists})` };
  base.phase = phase;

  const pair = findPairForInputMint(pairs, inputMint.toBase58());
  if (!pair) return { ...base, phase: "skip", skipReason: "no-active-pair-for-input-mint" };
  const outputMint = new PublicKey(pair.output_mint);
  base.outputMint = outputMint.toBase58();
  const matchedAmount = pair.max_output_base_units;
  const outputAmount = matchedAmount;
  base.matchedAmount = matchedAmount;
  base.outputAmount = outputAmount;
  if (BigInt(depositedAmount) > BigInt(pair.max_input_base_units))
    return { ...base, phase: "skip", skipReason: "deposit-exceeds-pair-max" };
  if (!(outputAmount > 0 && BigInt(outputAmount) <= depositedAmount))
    return { ...base, phase: "skip", skipReason: "output-amount-exceeds-deposit" };
  if (outputAmount > pair.max_quote_size_base_units)
    return { ...base, phase: "skip", skipReason: "output-exceeds-max-quote-size" };

  if (phase === "full" && expired) return { ...base, phase: "skip", skipReason: "expired" };
  if (phase === "full" && vaultStatus !== VAULT_STATUS_DEPOSITED)
    return { ...base, phase: "skip", skipReason: "vault-not-deposited" };

  const solverOutputSource = deriveAta(solver, outputMint);
  base.solverOutputAta = solverOutputSource.toBase58();
  const oSrc = await readTokenAccount(connection, solverOutputSource);
  const required = outputAmount + pair.reserve_floor_base_units;
  base.inventoryRequired = required;
  base.solverOutputBalance = oSrc ? oSrc.amount.toString() : null;
  const inventoryOk = !!oSrc && oSrc.mint.equals(outputMint) && oSrc.owner.equals(solver) && oSrc.amount >= BigInt(required);
  base.inventoryOk = inventoryOk;
  if (!inventoryOk) return { ...base, phase: "skip", skipReason: "insufficient-inventory" };

  const traderOutputDest = deriveAta(trader, outputMint);
  base.traderOutputAta = traderOutputDest.toBase58();
  const oDst = await readTokenAccount(connection, traderOutputDest);
  const traderAtaOk = !!oDst && oDst.mint.equals(outputMint) && oDst.owner.equals(trader);
  base.traderAtaOk = traderAtaOk;
  if (!traderAtaOk) return { ...base, phase: "skip", skipReason: "trader-output-ata-missing" };

  let fillHash: Buffer;
  if (phase === "resume-settle") {
    if (!matchInfo) return { ...base, phase: "skip", skipReason: "match-record-missing-on-resume" };
    const matchStatus = readU8(matchInfo.data, MATCH_STATUS_OFFSET);
    const recMatched = readU64LE(matchInfo.data, MATCH_MATCHED_AMOUNT_OFFSET);
    if (matchStatus !== LOCK_MATCH_STATUS_FILLED)
      return { ...base, phase: "skip", skipReason: `match-not-filled(status=${matchStatus})` };
    if (recMatched !== BigInt(outputAmount))
      return { ...base, phase: "skip", skipReason: `output-amount!=record(${recMatched})` };
    fillHash = Buffer.from(matchInfo.data.subarray(MATCH_FILL_HASH_OFFSET, MATCH_FILL_HASH_OFFSET + 32));
  } else {
    fillHash = deriveMatchFillHash(intentPda, matchedAmount);
  }
  base.fillHash = fillHash.toString("hex");

  const solverInputDest = deriveAta(solver, inputMint);
  base.solverInputDest = solverInputDest.toBase58();

  if (phase === "full") {
    base.matchBuilt = buildMatchEscrowedIx({ programId, intentPda, solver, matchedAmount, fillHash });
  }
  base.settleBuilt = buildSettleTwoSidedIx({
    programId, intentPda, solver, outputAmount, fillHash, vaultTokenAccount,
    solverOutputSource, traderOutputDest, solverInputDest,
  });
  return base;
}
function fmtKeys(keys: AccountMeta[]): string {
  return keys.map((k, i) => `      [${i}] ${k.pubkey.toBase58()} ${k.isSigner ? "S" : "-"}${k.isWritable ? "W" : "-"}`).join("\n");
}
function printPlan(plan: IntentPlan): void {
  const verdict =
    plan.phase === "full" || plan.phase === "resume-settle" ? `ACTIONABLE(${plan.phase})`
    : plan.phase === "done" ? "DONE" : `SKIP(${plan.skipReason})`;
  console.log(`- intent=${plan.intentPda} [${verdict}]`);
  console.log(`    trader=${plan.trader} status=${plan.intentStatus} expired=${plan.expired} match_exists=${plan.matchExists}`);
  console.log(`    input_mint=${plan.inputMint} output_mint=${plan.outputMint}`);
  console.log(`    deposited=${plan.depositedAmount} matched_amount=${plan.matchedAmount} output_amount=${plan.outputAmount}`);
  console.log(`    inventory: solver_output_ata=${plan.solverOutputAta} balance=${plan.solverOutputBalance} required=${plan.inventoryRequired} ok=${plan.inventoryOk}`);
  console.log(`    trader_output_ata=${plan.traderOutputAta} ok=${plan.traderAtaOk}`);
  if (plan.matchBuilt) {
    console.log(`    WOULD MATCH  data=${plan.matchBuilt.data.toString("hex")}`);
    console.log(`      fill_hash=${plan.fillHash}`);
    console.log(fmtKeys(plan.matchBuilt.keys));
  }
  if (plan.settleBuilt) {
    console.log(`    WOULD SETTLE data=${plan.settleBuilt.data.toString("hex")}`);
    console.log(fmtKeys(plan.settleBuilt.keys));
  }
}

// ===================== Signing (env keypair) =====================
let SIGNER: anchor.web3.Keypair | null = null;
async function sendIx(
  connection: anchor.web3.Connection,
  programIxLabel: string,
  ix: anchor.web3.TransactionInstruction,
  solver: PublicKeyT
): Promise<string> {
  if (!SIGNER) throw new Error(`no signer loaded (SOLVER_SECRET_KEY); refusing to send ${programIxLabel}.`);
  if (!SIGNER.publicKey.equals(solver)) {
    throw new Error(`loaded wallet ${SIGNER.publicKey.toBase58()} != solver ${solver.toBase58()}; refusing to send ${programIxLabel}.`);
  }
  const { blockhash, lastValidBlockHeight } = await connection.getLatestBlockhash();
  const tx = new Transaction({ feePayer: solver, blockhash, lastValidBlockHeight }).add(ix);
  tx.sign(SIGNER);
  const signature = await connection.sendRawTransaction(tx.serialize());
  await connection.confirmTransaction({ signature, blockhash, lastValidBlockHeight }, "confirmed");
  return signature;
}
async function executePlan(
  connection: anchor.web3.Connection, programId: PublicKeyT, plan: IntentPlan, solver: PublicKeyT
): Promise<void> {
  const intentPda = new PublicKey(plan.intentPda);
  if (plan.phase === "full") {
    if (!plan.matchBuilt || !plan.settleBuilt) throw new Error("full phase missing built ix");
    const matchSig = await sendIx(connection, "match_locked_intent_escrowed", plan.matchBuilt.ix, solver);
    console.log(`    match_signature=${matchSig}`);
    const after = await connection.getAccountInfo(intentPda);
    const st = after ? readU8(after.data, INTENT_STATUS_OFFSET) : -1;
    console.log(`    intent_status_after_match=${st} matched_escrowed=${st === STATUS_MATCHED_ESCROWED}`);
    if (st !== STATUS_MATCHED_ESCROWED) throw new Error(`match did not advance status to MATCHED_ESCROWED (got ${st}); aborting settle.`);
  }
  if (!plan.settleBuilt) throw new Error("missing settle ix");
  const settleSig = await sendIx(connection, "settle_two_sided", plan.settleBuilt.ix, solver);
  console.log(`    settle_signature=${settleSig}`);
  const after = await connection.getAccountInfo(intentPda);
  const st = after ? readU8(after.data, INTENT_STATUS_OFFSET) : -1;
  console.log(`    intent_status_after_settle=${st} settled=${st === STATUS_SETTLED}`);
}

// ===================== Poll loop =====================
let stopping = false;
function sleepInterruptible(ms: number): Promise<void> {
  return new Promise((resolve) => {
    const start = Date.now();
    const iv = setInterval(() => {
      if (stopping || Date.now() - start >= ms) { clearInterval(iv); resolve(); }
    }, 250);
  });
}
async function withRetry<T>(label: string, fn: () => Promise<T>): Promise<T> {
  let lastErr: unknown;
  for (let attempt = 1; attempt <= RETRY_ATTEMPTS; attempt++) {
    try { return await fn(); }
    catch (err) {
      lastErr = err;
      const msg = String(err && (err as any).message ? (err as any).message : err);
      if (attempt < RETRY_ATTEMPTS) {
        const backoff = RETRY_BASE_MS * 2 ** (attempt - 1);
        console.log(`    [retry] ${label} attempt ${attempt}/${RETRY_ATTEMPTS} failed: ${msg} — backing off ${backoff}ms`);
        await sleepInterruptible(backoff);
        if (stopping) throw err;
      } else {
        console.log(`    [retry] ${label} attempt ${attempt}/${RETRY_ATTEMPTS} failed: ${msg} — giving up this sweep`);
      }
    }
  }
  throw lastErr;
}
interface TickSummary { found: number; actionable: number; acted: number; skipped: number; errors: number; sweepFailed: boolean; }
async function runSweep(
  connection: anchor.web3.Connection, programId: PublicKeyT, pairs: PairConfig[], solver: PublicKeyT,
  mode: "execute" | "dry-run"
): Promise<TickSummary> {
  const summary: TickSummary = { found: 0, actionable: 0, acted: 0, skipped: 0, errors: 0, sweepFailed: false };
  let discovered;
  try { discovered = await withRetry("discovery", async () => discoverActionableIntents(connection, programId)); }
  catch (err) {
    const msg = String(err && (err as any).message ? (err as any).message : err);
    console.log(`  sweep failed (discovery): ${msg} — will retry next tick`);
    summary.sweepFailed = true;
    return summary;
  }
  summary.found = discovered.length;
  const actionable = discovered.filter((d) => d.actionable);
  summary.actionable = actionable.length;
  for (const d of actionable) {
    if (stopping) { console.log("  shutdown requested — stopping before next intent (current sweep partial)."); break; }
    try {
      const plan = await planIntentFlow(connection, programId, new PublicKey(d.intentPda), pairs, solver);
      printPlan(plan);
      const isActionable = plan.phase === "full" || plan.phase === "resume-settle";
      if (!isActionable) { summary.skipped += 1; continue; }
      if (mode === "execute") { await executePlan(connection, programId, plan, solver); summary.acted += 1; }
      else { console.log("    (dry-run: sent nothing)"); summary.acted += 1; }
    } catch (err) {
      const msg = String(err && (err as any).message ? (err as any).message : err);
      console.log(`  intent ${d.intentPda} errored: ${msg} — left for next sweep (idempotent resume).`);
      summary.errors += 1;
    }
  }
  summary.skipped += discovered.length - actionable.length;
  return summary;
}

function resolveRpcUrl(argv: string[]): string {
  const i = argv.indexOf("--url");
  if (i !== -1 && argv[i + 1]) return argv[i + 1];
  return process.env.DEVNET_RPC_URL || DEFAULT_RPC_URL;
}
function resolveStrArg(argv: string[], flag: string, fallback: string): string {
  const i = argv.indexOf(flag);
  return (i !== -1 && argv[i + 1] ? argv[i + 1] : undefined) || fallback;
}

// Build the signing keypair from SOLVER_SECRET_KEY (JSON byte array). Returns null if
// not supplied (allowed only in dry-run). The secret bytes are never logged.
function loadSignerFromEnv(): anchor.web3.Keypair | null {
  const raw = process.env.SOLVER_SECRET_KEY || "[]";
  let secretKey: number[];
  try { secretKey = JSON.parse(raw); }
  catch { throw new Error("SOLVER_SECRET_KEY is not valid JSON (expected a byte array)."); }
  if (!Array.isArray(secretKey) || secretKey.length === 0) return null;
  return Keypair.fromSecretKey(Uint8Array.from(secretKey));
}

async function run(): Promise<number> {
  const argv = process.argv.slice(2);
  const rpcUrl = resolveRpcUrl(argv);
  const programId = new PublicKey(resolveStrArg(argv, "--program", PROGRAM_ID));
  const solver = new PublicKey(EXPECTED_SOLVER);
  const connection = new Connection(rpcUrl, "confirmed");
  const intervalMs = Number(resolveStrArg(argv, "--interval-ms", String(POLL_INTERVAL_MS)));
  const maxTicks = Number(resolveStrArg(argv, "--max-ticks", "0")); // 0 = run forever

  const flagExecute = argv.includes(EXECUTE_FLAG);
  const envAllow = process.env[EXECUTE_GUARD_ENV] === EXECUTE_GUARD_TOKEN;
  const mode: "execute" | "dry-run" = flagExecute && envAllow ? "execute" : "dry-run";

  SIGNER = loadSignerFromEnv();
  if (mode === "execute" && !SIGNER) {
    throw new Error("execute mode requires SOLVER_SECRET_KEY (a JSON byte array) to be set.");
  }
  if (SIGNER && !SIGNER.publicKey.equals(solver)) {
    throw new Error(`SOLVER_SECRET_KEY pubkey ${SIGNER.publicKey.toBase58()} != EXPECTED_SOLVER ${solver.toBase58()}; refusing to start.`);
  }

  console.log("ShadeIntent Railway Solver starting...");
  console.log("Solver pubkey:", (SIGNER ? SIGNER.publicKey : solver).toBase58());
  console.log("RPC:", rpcUrl);
  console.log("Execute mode:", process.env[EXECUTE_GUARD_ENV] === EXECUTE_GUARD_TOKEN);
  console.log(`program_id=${programId.toBase58()} poll_interval_ms=${intervalMs} max_ticks=${maxTicks || "∞"} mode=${mode}`);
  if (flagExecute !== envAllow) {
    console.log(`note: a send requires BOTH ${EXECUTE_FLAG} AND ${EXECUTE_GUARD_ENV}=${EXECUTE_GUARD_TOKEN}; one present -> dry-run.`);
  }

  const onSignal = (sig: string) => {
    if (stopping) return;
    stopping = true;
    console.log(`\n[${sig}] shutdown requested — finishing current intent, then exiting...`);
  };
  process.on("SIGINT", () => onSignal("SIGINT"));
  process.on("SIGTERM", () => onSignal("SIGTERM"));

  // Serve only THIS solver's pairs.
  const pairs = PAIRS.filter((p) => p.solver_wallet === solver.toBase58());
  console.log(`pairs_loaded=${pairs.length}/${PAIRS.length} for solver ${solver.toBase58()} (${pairs.map((p) => p.pair_id).join(",") || "none"})`);
  if (pairs.length === 0) console.log("WARNING: no active pairs match this solver_wallet — nothing will be actionable.");

  let tick = 0;
  while (!stopping && (maxTicks === 0 || tick < maxTicks)) {
    tick += 1;
    const ts = new Date().toISOString();
    console.log(`\n--- tick ${tick} @ ${ts} ---`);
    const s = await runSweep(connection, programId, pairs, solver, mode);
    console.log(`tick ${tick} summary: found=${s.found} actionable=${s.actionable} acted=${s.acted} skipped=${s.skipped} errors=${s.errors} sweep_failed=${s.sweepFailed}`);
    if (stopping) break;
    if (maxTicks !== 0 && tick >= maxTicks) break;
    await sleepInterruptible(intervalMs);
  }
  console.log(`\nshutdown complete: ran ${tick} tick(s), mode=${mode}. No state held; safe to restart.`);
  console.log("SERVICE_RESULT=STOPPED");
  return 0;
}

if (require.main === module) {
  run()
    .then((code) => process.exit(code))
    .catch((err) => {
      console.error("SERVICE_RESULT=ERROR");
      console.error(String(err && err.message ? err.message : err));
      process.exit(1);
    });
}
